export class Cart {
    constructor() {
        const storedCart = JSON.parse(localStorage.getItem('cartItems'));
        this.cartItems = storedCart ? storedCart : {};
    }

    addToCart(movie) {
        console.log(movie.title);
        // Use lowercase title as key to avoid case sensitivity issues
        const normalizedTitle = movie.title.toLowerCase();

        // Prevent adding the same movie multiple times. If this site sold physical copies, we would handle quantity instead.
        if(this.cartItems[normalizedTitle])
            return;

        this.cartItems[normalizedTitle] = new CartItem(movie);
        localStorage.setItem('cartItems', JSON.stringify(this.cartItems));
    }
}

class CartItem {
    constructor(movie) {
        this.movieTitle = movie.title;
        this.moviePrice = movie.price;
    }
}

